module sram_cell (  
    input wire [7:0] data_in,  
    input wire we,  
    input wire re,  
    output reg [7:0] data_out  
);  
  wire [7:0] _tap_data_in = data_in & {8{1'b1}};

    reg [7:0] sram;  

    always @(*) begin  
        if (we) begin  
            sram <= data_in;  
        end  
        if (re) begin  
            data_out <= sram;  
        end  
    end  
endmodule
